document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll('[data-x="location"] .js-select-control-button').forEach(button=>{button.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();const slug=button.dataset.slug;const name=button.dataset.name;document.querySelector('[data-x-click="location"] .js-select-control-chosen').textContent=name;document.querySelector('#location_slug').value=slug})});document.querySelectorAll('[data-x="tour-type"] .js-select-control-button').forEach(button=>{button.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();const slug=button.dataset.slug;const name=button.dataset.name;document.querySelector('[data-x-click="tour-type"] .js-select-control-chosen').textContent=name;document.querySelector('#tour_category_slug').value=slug})});document.getElementById('applyCustomGroupSize')?.addEventListener('click',()=>{const min=document.getElementById('customMinGroupSize').value;const max=document.getElementById('customMaxGroupSize').value;let label='Any size';if(min||max){label=`${min || '1'} - ${max || '+'}`}
document.querySelector('[data-x-click="group_size"] .js-select-control-chosen').textContent=label;document.querySelector('#group_size_min').value=min;document.querySelector('#group_size_max').value=max});document.querySelectorAll(".js-testimonials-slider").forEach(sliderEl=>{const slider=new Swiper(sliderEl,{slidesPerView:1,loop:!0,autoplay:{delay:5000,disableOnInteraction:!1,},pagination:{el:sliderEl.querySelector('.'+sliderEl.dataset.pagination),clickable:!0,},})})})